import { NoSuchModelError } from '@ai-sdk/provider';
import { beforeEach, describe, expect, it, vi } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';
import { createPixelArt } from './pixelart-provider';

vi.mock('./pixelart-image-model', () => ({
  PixelArtImageModel: vi.fn(),
}));

describe('createPixelArt', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('image()', () => {
    it('should construct an image model with default configuration', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });

      provider.image('pixelart-v1');

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        'pixelart-v1',
        expect.objectContaining({
          provider: 'pixelart.image',
          baseURL: 'https://api.pixelart.ai/v1',
        }),
      );
    });

    it('should return an instance of PixelArtImageModel', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.image('pixelart-v1');

      expect(model).toBeInstanceOf(PixelArtImageModel);
    });

    it('should respect a custom baseURL', () => {
      const provider = createPixelArt({
        apiKey: 'test-key',
        baseURL: 'https://custom.pixelart.ai/v2',
      });

      provider.image('pixelart-v1');

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        'pixelart-v1',
        expect.objectContaining({
          baseURL: 'https://custom.pixelart.ai/v2',
        }),
      );
    });

    it('should strip trailing slash from baseURL', () => {
      const provider = createPixelArt({
        apiKey: 'test-key',
        baseURL: 'https://custom.pixelart.ai/v2/',
      });

      provider.image('pixelart-v1');

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        'pixelart-v1',
        expect.objectContaining({
          baseURL: 'https://custom.pixelart.ai/v2',
        }),
      );
    });

    it('should forward custom fetch to the model', () => {
      const mockFetch = vi.fn();
      const provider = createPixelArt({ apiKey: 'test-key', fetch: mockFetch });

      provider.image('pixelart-v1');

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        'pixelart-v1',
        expect.objectContaining({ fetch: mockFetch }),
      );
    });

    it('imageModel() should be an alias for image()', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });

      provider.imageModel('pixelart-v1-fast');

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        'pixelart-v1-fast',
        expect.objectContaining({ provider: 'pixelart.image' }),
      );
    });

    it('should support all known model IDs', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const modelIds = [
        'pixelart-v1',
        'pixelart-v1-fast',
        'retro-art-v1',
        '8bit-art-v1',
      ] as const;

      for (const modelId of modelIds) {
        vi.clearAllMocks();
        provider.image(modelId);
        expect(PixelArtImageModel).toHaveBeenCalledWith(
          modelId,
          expect.objectContaining({ provider: 'pixelart.image' }),
        );
      }
    });
  });

  describe('languageModel()', () => {
    it('should throw NoSuchModelError', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });

      expect(() => provider.languageModel('any-model')).toThrow(
        NoSuchModelError,
      );
    });
  });

  describe('embeddingModel()', () => {
    it('should throw NoSuchModelError', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });

      expect(() => provider.embeddingModel('any-model')).toThrow(
        NoSuchModelError,
      );
    });
  });
});

